-- ---------- 011_audit_triggers.sql ----------
-- =============================================================================
-- Migration 011 — Auto-write audit_log triggers for AI/user-data tables.
--
-- The audit_log table exists since 001 but until now nothing writes to it from
-- application code. Per CLAUDE.md §8.6 every AI action must produce an audit
-- trail; the durable way to do that is at the database layer so a forgetful
-- caller cannot bypass it.
--
-- Triggers fire AFTER INSERT/UPDATE/DELETE on:
--   briefs, alerts, ai_calls, exchange_keys, holdings, theses
-- Each trigger writes a single audit_log row capturing the actor (best effort
-- from auth.uid()), the action, target table+pk, and a small summary jsonb.
-- =============================================================================

-- Generic audit-row builder. Each trigger passes (action, target_table, args).
create or replace function audit_log_write(
    p_action text,
    p_target text,
    p_args   jsonb default '{}'::jsonb,
    p_result jsonb default '{}'::jsonb
) returns void
language plpgsql
security definer
as $$
declare
    v_uid uuid := nullif(current_setting('request.jwt.claim.sub', true), '')::uuid;
begin
    insert into audit_log (user_id, actor, action, target, args_summary, result_summary)
    values (v_uid, case when v_uid is null then 'system' else 'user' end,
            p_action, p_target, p_args, p_result);
exception when others then
    -- Never let an audit failure block the underlying mutation.
    null;
end;
$$;

-- Generic AFTER trigger payload — uses TG_OP, TG_TABLE_NAME, NEW/OLD ids.
create or replace function audit_log_trg() returns trigger
language plpgsql
security definer
as $$
declare
    v_pk text;
    v_args jsonb;
begin
    if (TG_OP = 'DELETE') then
        v_pk := coalesce(OLD.id::text, '');
        v_args := jsonb_build_object('op', TG_OP, 'pk', v_pk);
    else
        v_pk := coalesce(NEW.id::text, '');
        v_args := jsonb_build_object('op', TG_OP, 'pk', v_pk);
    end if;
    perform audit_log_write(TG_OP || ':' || TG_TABLE_NAME, TG_TABLE_NAME, v_args);
    if (TG_OP = 'DELETE') then return OLD; else return NEW; end if;
end;
$$;

-- Wire the trigger to each tracked table. Use DO-block so we silently skip
-- tables that don't exist yet in fresh checkouts (e.g., ai_calls in unit dbs).
do $$
declare
    t text;
begin
    for t in select unnest(array['briefs','alerts','ai_calls','exchange_keys','holdings','theses'])
    loop
        if exists (select 1 from information_schema.tables where table_name = t) then
            execute format('drop trigger if exists audit_%I on %I', t, t);
            execute format(
                'create trigger audit_%I after insert or update or delete on %I '
                'for each row execute function audit_log_trg()', t, t);
        end if;
    end loop;
end $$;

-- ---------- 012_telegram_snooze.sql ----------
-- =============================================================================
-- 012 — Telegram snooze column on users
--
-- Adds `alerts_snoozed_until` so the /snooze command from the Telegram bot
-- can pause alert delivery without dropping rules. The alert_dispatcher
-- worker checks this before sending; the bot's /status command surfaces it.
-- =============================================================================

alter table users
    add column if not exists alerts_snoozed_until timestamptz;

create index if not exists users_telegram_chat_id_idx
    on users (telegram_chat_id)
    where telegram_chat_id is not null;

-- ---------- 013_ta_snapshots.sql ----------
-- =============================================================================
-- 013 — Token Technical-Analysis snapshots, captured at multiple timeframes.
--
-- The TA snapshotter worker writes one row per (token, timeframe, captured_at)
-- on a rolling cadence (1h / 3h / 6h / 12h). The /api/tokens/{symbol}/ta
-- endpoint returns the latest row per timeframe; the token deep-dive page
-- renders a 4-up panel showing how each TF reads the same chart.
-- =============================================================================

create table if not exists token_ta_snapshots (
    id              uuid primary key default uuid_generate_v4(),
    token_id        uuid not null references tokens(id) on delete cascade,
    symbol          text not null,           -- denormalized for fast filter
    timeframe       text not null check (timeframe in ('1h','3h','6h','12h','1d')),
    captured_at     timestamptz not null default now(),
    -- Compact decision fields (the verdict the worker decided)
    stance          text not null check (stance in ('long','short','neutral','no-data')),
    confidence      numeric(4,3),            -- 0..1
    composite_score numeric(5,2),            -- 0..10
    -- Reference levels for entry / risk planning
    last_price      numeric(28,8),
    suggested_entry numeric(28,8),
    suggested_stop  numeric(28,8),
    suggested_target numeric(28,8),
    risk_reward     numeric(6,2),
    atr_pct         numeric(6,3),
    -- Indicator + pattern + structure summary as jsonb so the schema doesn't
    -- have to evolve every time we add a new feature.
    summary         jsonb not null default '{}'::jsonb,
    -- Free-form analyst notes (which patterns hit, which divergences, etc).
    rationale       text[],
    unique (token_id, timeframe, captured_at)
);
create index if not exists ta_snapshots_token_tf_ts on token_ta_snapshots (token_id, timeframe, captured_at desc);
create index if not exists ta_snapshots_symbol_tf_ts on token_ta_snapshots (symbol, timeframe, captured_at desc);
create index if not exists ta_snapshots_recent on token_ta_snapshots (captured_at desc);

-- Public-read; the data is non-PII and the same numbers anyone can compute
-- from public OHLCV. Writes only via service-role (workers).
alter table token_ta_snapshots enable row level security;
create policy "ta_snapshots public read" on token_ta_snapshots
  for select using (true);

-- =============================================================================
-- Trading-bot decisions: one row per (token, cycle), composed from every
-- signal we have. The bot worker writes here every hour.
-- =============================================================================
create table if not exists bot_decisions (
    id              uuid primary key default uuid_generate_v4(),
    token_id        uuid not null references tokens(id) on delete cascade,
    symbol          text not null,
    decided_at      timestamptz not null default now(),
    horizon         text not null check (horizon in ('swing','position','long')),
    stance          text not null check (stance in ('long','short','neutral','watch')),
    confidence      numeric(4,3),            -- 0..1
    composite_score numeric(5,2),            -- 0..10
    -- Risk plan
    last_price      numeric(28,8),
    suggested_entry numeric(28,8),
    suggested_stop  numeric(28,8),
    suggested_target numeric(28,8),
    risk_reward     numeric(6,2),
    -- Inputs that fed the decision (so we can audit / explain)
    inputs          jsonb not null default '{}'::jsonb,
    -- Human-readable reasoning bullets
    reasoning       text[],
    -- Hard invalidation conditions (what would flip this decision)
    invalidation    text[]
);
create index if not exists bot_decisions_token_ts on bot_decisions (token_id, decided_at desc);
create index if not exists bot_decisions_symbol_ts on bot_decisions (symbol, decided_at desc);

alter table bot_decisions enable row level security;
create policy "bot_decisions public read" on bot_decisions
  for select using (true);
